/* eslint-disable class-methods-use-this */
import * as THREE from 'three';
import { ImageTracker } from '../defaultpipeline.js';
/**
 * Loader for image trackers.
 * @see https://docs.zap.works/universal-ar/web-libraries/threejs/image-tracking/
 */
export class ImageTrackerLoader extends THREE.Loader {
    // Implementation that handles both signatures
    load(zpt, onLoadCallback, onProgressCallback, onErrorCallback) {
        // Check if we're using the new required pattern
        // (onLoad is required and onProgress has expected signature if provided)
        const isNewPattern = typeof onLoadCallback === 'function' && (!onProgressCallback || onProgressCallback.length !== 0);
        if (isNewPattern) {
            // Handle as new-style (void return)
            const onLoad = onLoadCallback;
            const trk = new ImageTracker();
            this.manager.itemStart(zpt);
            trk
                .loadTarget(zpt)
                .then(() => {
                onLoad(trk);
                this.manager.itemEnd(zpt);
            })
                .catch(err => {
                if (onErrorCallback)
                    onErrorCallback(err);
                this.manager.itemError(zpt);
                this.manager.itemEnd(zpt);
            });
            return;
        }
        else {
            // Original implementation (returns ImageTracker)
            const onLoad = onLoadCallback;
            const onError = onErrorCallback;
            const trk = new ImageTracker();
            this.manager.itemStart(zpt);
            trk
                .loadTarget(zpt)
                .then(() => {
                if (onLoad)
                    onLoad(trk);
                this.manager.itemEnd(zpt);
            })
                .catch(_ => {
                if (onError)
                    onError(_);
                this.manager.itemError(zpt);
                this.manager.itemEnd(zpt);
            });
            return trk;
        }
    }
    /**
     * @ignore
     */
    parse() { }
}
